import{i as a,f as e,o as t,aN as s}from"./chunks/framework.o4RMrJe2.js";const o="/docs/assets/e51ec265a0a73de1c9084c03e00c064.a4cTgD5V.jpg",i="/docs/assets/8575450e203ae6cd1da4bcbaedb1f4c.3VyITSVE.jpg",r="/docs/assets/0a9e760b8cda6302f5b9b75d8d20e2e.VES827Ib.jpg",c="/docs/assets/a799a221193e4b3276e329fd916d805.IEROHQax.jpg",d="/docs/assets/8a690c9d2269e0ace3cc365a8cede26.ganVLnxu.jpg",l="/docs/assets/30b439fb896c55a23ae667eb757da7c.SNJSgqfw.jpg",p="/docs/assets/d807cd14e24ba3d07869a98083b0f60.uUS0Qfyv.jpg",n="/docs/assets/8828c95857f4b9587b65ac366ef6a1f.L5oaHw-H.jpg",h="/docs/assets/c0b65bd5900a2b683efee8e19f5acaa.5E3dPHGp.jpg",_="/docs/assets/94175adb72da82e9e5fddc2a198c362c_v2-51ecae55dff53ee75a7bb2fdcea3c5d4_720w_source_1def8aca.tYWxLm__.webp",u="/docs/assets/317fafa824ddeff41b8c6fc2fd7d5ea3_v2-a3a293af334661d840ce7a920e91bb6d_720w_source_1def8aca.903UHHI-.webp",f="/docs/assets/8f855a9849d854011293b96513ea772.qKb6UTKy.jpg",y=JSON.parse('{"title":"沪漂经历 （可当短篇小说观赏）","description":"","frontmatter":{},"headers":[],"relativePath":"column/Growing/index.md","filePath":"column/Growing/index.md","lastUpdated":1718172934000}'),m={name:"column/Growing/index.md"},b=s('<h1 id="沪漂经历-可当短篇小说观赏" tabindex="-1">沪漂经历 （可当短篇小说观赏） <a class="header-anchor" href="#沪漂经历-可当短篇小说观赏" aria-label="Permalink to &quot;沪漂经历 （可当短篇小说观赏）&quot;">​</a></h1><h2 id="这篇文章讲述了作者平凡朴素的生活-以及他如何通过自己的奋斗-过上了穷人的日子。" tabindex="-1">这篇文章讲述了作者平凡朴素的生活，以及他如何通过自己的奋斗，过上了穷人的日子。 <a class="header-anchor" href="#这篇文章讲述了作者平凡朴素的生活-以及他如何通过自己的奋斗-过上了穷人的日子。" aria-label="Permalink to &quot;这篇文章讲述了作者平凡朴素的生活，以及他如何通过自己的奋斗，过上了穷人的日子。&quot;">​</a></h2><h3 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h3><p>我是一枚🎓专科应届生👩‍🎓，对前端开发🧑‍💻有着浓厚的兴趣。在大学期间，我通过自学📖掌握了一些前端知识📚，并希望在未来从事相关工作💼。 不太爱运动🏃。在游戏方面🎮，我更喜欢玩手游📱，例如王者🦁、原神🧝‍和蛋仔🥚等休闲游戏🎰。</p><div style="display:flex;justify-content:space-around;"><img style="width:30%;" src="'+o+'"><img style="width:30%;" src="'+i+'"><img style="width:30%;" src="'+r+'"></div><p>📧刚来上海不久，就遭遇了上海疫情爆发。前三个月的线上面试，让我遇到了不少奇葩的面试官，当然也有很多不错的。而我的起点，也正是从这里开始。 时隔两年，我有很多想法想和大家分享🤗，也希望大家能多提宝贵意见🙏。</p><h3 id="_2022年2月" tabindex="-1">2022年2月 <a class="header-anchor" href="#_2022年2月" aria-label="Permalink to &quot;2022年2月&quot;">​</a></h3><p>在疫情爆发的前一周，我已准备好并投出了第一批简历。第一周我面试了两家公司，一家是租房平台的互联网公司，另一家是自研数字展屏和开发小程序的小公司，员工总数大概有七八个，主要是 90 后和 00 后的年轻人。我拿到的是自研公司的 offer，半年调一次薪。由于担心疫情会减少后续的面试机会，经过深思熟虑，我还是选择了这家公司。然而，好景不长…… <img src="'+c+'" alt="Alt text"></p><h4 id="两天后。。" tabindex="-1">两天后。。 <a class="header-anchor" href="#两天后。。" aria-label="Permalink to &quot;两天后。。&quot;">​</a></h4><p>😱上海的疫情😷正式爆发，所有人都居家办公🧑‍💻。当时我才入职两天，刚把环境安装好、代码和第三方接口调用文档看的差不多的时候📑，就被通知不用去公司也用不到我了，我丢！原因的话就是因为公司疫情小程序业务线上停止运行📴，说白了就是公司没钱了，所以就拜拜了🙏。 <img src="'+d+'" alt="Alt text"></p><h3 id="_2022年3月" tabindex="-1">2022年3月 <a class="header-anchor" href="#_2022年3月" aria-label="Permalink to &quot;2022年3月&quot;">​</a></h3><p>疫情期间，我不得不重新开始找工作🤔。由于疫情的影响，面试机会变得非常少，基本上都是线上的面试🖥。然而，我却遇到了一家奇葩的公司😲。接下来，让我们看看发生了什么🧐。</p><h3 id="_2022年4月-上海xx公司产品经理提桶跑路" tabindex="-1">2022年4月 上海XX公司产品经理提桶跑路 <a class="header-anchor" href="#_2022年4月-上海xx公司产品经理提桶跑路" aria-label="Permalink to &quot;2022年4月 上海XX公司产品经理提桶跑路&quot;">​</a></h3><p>🖥我参加了一家“只有三个人的小公司”的线上面试。对接我的是一位自称产品经理的马克😒。🙂面试时，技术和人事方面的问题都已经商量好了，他说让我试用一周，如果通过考核就可以转正。听到这里，我心想：这样挺好的。🤔然后他又问我是否可以半夜起来加班，我😲想都没想就爽快地答应了…… <img src="'+l+'" alt="Alt text"> 之后的一周，我每天十点起床上班，一直工作到凌晨五点🕔。和我同住的同事看到我这么晚还在加班，非常震惊😲。这些工作对我来说没有太大难度，就是改改样式、调整逻辑。周五的时候，他们说要跟我开会聊一下📋。由于他们没有透露过自己的名字，一直用昵称交流，所以他们说：“我们商量后决定不招人了。”那我想，你不招人那就结算工资算了呗，然后当我提这事时，没想到他们仨直接跑了🚶，群里就剩我一个，加微信的人还把我删了😒。当时我是在 BOSS 上认识他们的，同事让我去仲裁，当时太年轻，仲裁勇气欠缺，就只是在 BOSS简单的提交证明举报了他们🚫。其实也没啥太大的用处（其实就是为了自我安慰），BOSS 上需要裁定书才能封杀这家公司，就当做给自己个教训（兄弟们可别学我，遇到事一定要上，夺回本属于自己的权利!） <img src="'+p+'" alt="Alt text"></p><h3 id="面对此类公司解决办法" tabindex="-1">面对此类公司解决办法 <a class="header-anchor" href="#面对此类公司解决办法" aria-label="Permalink to &quot;面对此类公司解决办法&quot;">​</a></h3><p>结束后我复盘了一下，当时我也没有想太多，就想着先找份工作再说，因为当时我还没有毕业，等毕业了之后再做其他打算。 下次遇到此类问题我想到一些解决方案：</p><ul><li>每次面试时把录音打开</li><li>把每次沟通的聊天记录提取出来</li><li>该在面试的时候问的所有问题都要了解确定清楚，避免发生如上事件</li><li>加夜班的公司一律不接受</li><li>面试前提前从企查查上面了解公司情况，查不到的公司就留一份心</li></ul><h3 id="_2022年5月-拿下xx公司offer并入职" tabindex="-1">2022年5月 拿下XX公司offer并入职 <a class="header-anchor" href="#_2022年5月-拿下xx公司offer并入职" aria-label="Permalink to &quot;2022年5月 拿下XX公司offer并入职&quot;">​</a></h3><p>到了五月份，能约到的面试寥寥无几，而且都是线上进行😒。其中有一家条件还不错的小公司，视频会议时了解到这家公司主要与上海的医院合作📱，主要的话是负责制作官网，其次也会做一些微信小程序或 H5。，面试结束后还有机试，也就一些简单的网站特效，之后我就正常通过了。工资也在基本范围内，而且暂时也不考虑其他公司的情况，就正常入职了。撒花🎉🎉🎉 <img src="'+n+'" alt="alt text"></p><h3 id="结尾" tabindex="-1">结尾 <a class="header-anchor" href="#结尾" aria-label="Permalink to &quot;结尾&quot;">​</a></h3><p>2023 年，公司计划稍微向 AR 和建模方向发展。整体下来没什么大的改变，可能因为国家要查一些医院导致项目变少，在小公司苟活。 2024 年，公司如果未好转，那么注定只能去换家公司（有兄弟内推的话哎我真的是感激不尽）。 <img src="'+h+'" alt="alt text"></p><h3 id="关于面试题" tabindex="-1">关于面试题 <a class="header-anchor" href="#关于面试题" aria-label="Permalink to &quot;关于面试题&quot;">​</a></h3><p>这边的面试，这里总结了一些，基本都是在面试中经常问到的。（仅供参考！！！）</p><p>三月份到四月份，因为疫情爆发迅速，导致这里停工了很多，找工作的机会比较的困难，只能通过线上去面试。一共面试了五家，总结如下。</p><p>html：http协议（四家有三家问到），web常见的攻击方式有哪些，xss攻击会造成什么问题。DNS是什么（提到域名翻译成ip地址即可），http和https的区别，状态码能说出几种，304状态是做什么的</p><p>css：定位的几种方式（好几家给的答案不一样，一共五种）absolute、relative、fixed、static（默认）、sticky（粘性）；垂直居中（最好讲出三种以上）</p><p>js合并对象的方式，数组求和，增删改查的操作，splice怎么使用，数组怎么转对象，对象怎么转数组，对象如何合并，数组如何合并，基本数据类型和引用数据类型的区别，递归。</p><p>es6：es6有哪些新特性，Promise是什么（提到resolve，rejected成功为then，失败为catch）</p><p>Vue方面：问了路由的两种模式，hash和history的区别(三种)，什么是同源，什么是不同源；跨域的几种方式（jsonp，proxy，websocket），watch和computed的区别，vuex的五种状态，mutations的用法，mutations和actions的区别，路由怎么传参，parmas和query的区别，路由怎么跳转，双向绑定的实现原理，常用的生命周期是哪三个（created，mounted，activated ），组件通信的方式有哪些，vue的生命周期（一定要说keepalive中的两个），keep-alive中的include和exclude的区别，里面可以写什么（正则和字符串），如何保持页面刷新之后内容不会掉，页面写一个数据跳转路由过后再次返回，里面的数据还在可以用哪些方式（sessionStorage，websocket，keep-alive），vuex的场景有哪些， router.addRoutes里面传什么（&#39;父路由&#39;,遍历后的子路由）</p><p>大数据可视化，echarts：常见的几种属性。用的什么适配方法（rem+媒体查询）</p><p>小程序：用过的第三方ui框架有哪些（uview或者原生），小程序常用的生命周期，打包出现大于2MB该如何解决，打包上线的流程是什么（要提到appid和不校验合法域名）。</p><p>后管（中台）系统：token是存放在哪里的？动态路由一般用在哪里的，登陆后如何判断有没有权限，前置导航守卫中的to，from，next分别是干嘛的，addroute具体怎么使用</p><p>其他的问题：ts了解过吗，jQuery的事件委托了解过吗，D3.js，three.js、Antdv框架、uview了解过吗</p><p>h5用了哪些（vant）？PC端用了哪些？（iview和element-ui），前端性能优化你做过哪些？</p><p>奇葩题目： <img src="'+_+'" alt="alt text"><img src="'+u+'" alt="alt text"></p><p>总结了一下，在我认为比较正规的面试中有三家问了技术，还有两家就是闲聊了一会。</p><p>对于面试的建议，在这里我想说，就是得多看面试题，注意一些小的细节性的提问。基本没什么问题，只要跟紧前端发展趋势，基本都可以胜任这份工作。在今年2024年我觉得他问的多的应该就是一些vue3的内容包括一些其他的库，目前比较火的应该是鸿蒙的ArkTS。想在前端基础上扩展出去的可以学一学鸿蒙开发，也没有想象中那么难，都是基于ts编写的代码。 <img src="'+f+'" alt="alt text"></p><h2 id="至今" tabindex="-1">至今 <a class="header-anchor" href="#至今" aria-label="Permalink to &quot;至今&quot;">​</a></h2><p>现在的话我暂时还是正常在上海某互联网公司工作，从事前端开发工程师。 后续在2024年可能会因工资和技术问题考虑更换工作。</p><h2 id="未来" tabindex="-1">未来 <a class="header-anchor" href="#未来" aria-label="Permalink to &quot;未来&quot;">​</a></h2><p>对于未来的规划，我打算提升学历，并在计算机领域深入学习，包括算法、计算机图形学、数据结构和游戏开发等。之后，我可能会涉足鸿蒙开发相关工作。这让我想起董宇辉说过的一句话：“有时会觉得努力无用，但若将人生放在更长远的维度去审视，就会发现它的价值。要有耐心，黎明前的黑暗是最浓重的，只要再坚持一下，天就会亮。”这句话提醒我们，在面对困境和挫折时，要保持耐心和积极的心态。有时，我们可能觉得努力并未立刻带来显著的成果，但从更长远的人生视角来看，我们的努力终将得到回报。无论之前再怎么样，从现在开始，一定会为了自己追求的兴趣爱好和梦想而努力，这辈子不算太差。</p>',41),x=[b];function g(q,k,v,P,w,S){return t(),e("div",null,x)}const A=a(m,[["render",g]]);export{y as __pageData,A as default};
